SELECT article_type, AVG(sentiment_score) as avg_sentiment_score
FROM news_articles
GROUP BY article_type;

SELECT na.stock_symbols, c.company_name, na.high_price
FROM news_articles na
JOIN companies c ON na.stock_symbols = c.stock_symbol;

SELECT article_text, timestamp, source_name, article_language
FROM news_articles
WHERE article_id BETWEEN 101 AND 199;

SELECT cf.*
FROM company_financials cf
WHERE cf.company_id = (SELECT company_id FROM companies WHERE company_name = 'Your Company Name');

SELECT DISTINCT users.user_name, users.role
FROM users
JOIN article_ratings ON users.user_id = article_ratings.user_id;
